INSERT INTO `v1_026e5b95fc1a2aad454f3bcf77a61bafb6199d18ea0c41e08d78a17d68ccb287` VALUES (1000, "vo_minigame_1013_icon_1_002_001", "vo_minigame_1013_icon_2_002_001", 2, 2, 1, 2, "調子が上がって\nきたなっ", 3000, "訓練はまだ\nここからですわ");
INSERT INTO `v1_026e5b95fc1a2aad454f3bcf77a61bafb6199d18ea0c41e08d78a17d68ccb287` VALUES (5000, "vo_minigame_1013_icon_1_003_001", "vo_minigame_1013_icon_2_003_001", 2, 2, 2, 2, "ほらほら、\nまだいけるだろ？", 3000, "クスクス、悪くない\n流れですわね");
INSERT INTO `v1_026e5b95fc1a2aad454f3bcf77a61bafb6199d18ea0c41e08d78a17d68ccb287` VALUES (10000, "vo_minigame_1013_icon_1_004_001", "vo_minigame_1013_icon_2_004_001", 2, 2, 3, 3, "へへっ、おまえら\nやるじゃねえか！", 3000, "すばらしい\n記録ですわ");
INSERT INTO `v1_026e5b95fc1a2aad454f3bcf77a61bafb6199d18ea0c41e08d78a17d68ccb287` VALUES (10000, "vo_minigame_1013_icon_1_005_001", "vo_minigame_1013_icon_2_005_001", 3, 2, 4, 3, "あたしたちはまだ\n止まらねえぜ！", 3000, "乗りに乗って\nいますわね");
INSERT INTO `v1_026e5b95fc1a2aad454f3bcf77a61bafb6199d18ea0c41e08d78a17d68ccb287` VALUES (10000, "vo_minigame_1013_icon_1_005_002", "vo_minigame_1013_icon_2_005_002", 3, 2, 5, 3, "見てろよ！\nマコト班の快進撃だ！", 3000, "まだまだ行きます\nついてきなさい");
INSERT INTO `v1_026e5b95fc1a2aad454f3bcf77a61bafb6199d18ea0c41e08d78a17d68ccb287` VALUES (10000, "vo_minigame_1013_icon_1_005_003", "vo_minigame_1013_icon_2_005_003", 3, 2, 6, 3, "うおぉぉっ！\n絶好調だぜ！", 3000, "エリコ班の\n本領発揮ですわ！");
INSERT INTO `v1_026e5b95fc1a2aad454f3bcf77a61bafb6199d18ea0c41e08d78a17d68ccb287` VALUES (0, "vo_minigame_1013_icon_1_006_001", "vo_minigame_1013_icon_2_006_001", 4, 2, 7, 3, "どこまで行けるか\n楽しみだなっ！", 3000, "ここからは\n前人未到の領域です！");
INSERT INTO `v1_026e5b95fc1a2aad454f3bcf77a61bafb6199d18ea0c41e08d78a17d68ccb287` VALUES (1, "vo_minigame_1013_icon_1_007_001", "vo_minigame_1013_icon_2_007_001", 5, 3, 8, 4, "まだ諦めんなよっ", 1000, "厄介でしたわ…");
INSERT INTO `v1_026e5b95fc1a2aad454f3bcf77a61bafb6199d18ea0c41e08d78a17d68ccb287` VALUES (1, "vo_minigame_1013_icon_1_007_002", "vo_minigame_1013_icon_2_007_002", 5, 3, 9, 4, "冷やっとしたぜ…！", 1000, "油断大敵です");
INSERT INTO `v1_026e5b95fc1a2aad454f3bcf77a61bafb6199d18ea0c41e08d78a17d68ccb287` VALUES (1, "vo_minigame_1013_icon_1_007_003", "vo_minigame_1013_icon_2_007_003", 5, 3, 10, 4, "弱音を吐くなっ", 1000, "忌々しいっ…");
INSERT INTO `v1_026e5b95fc1a2aad454f3bcf77a61bafb6199d18ea0c41e08d78a17d68ccb287` VALUES (99, "vo_minigame_1013_icon_1_008_001", "vo_minigame_1013_icon_2_008_001", 6, 4, 11, 3, "マコト班集合！", 1500, "大所帯ですわね");
INSERT INTO `v1_026e5b95fc1a2aad454f3bcf77a61bafb6199d18ea0c41e08d78a17d68ccb287` VALUES (99, "vo_minigame_1013_icon_1_008_002", "vo_minigame_1013_icon_2_008_002", 6, 4, 12, 3, "連携してくぞ！", 1500, "エリコ班へようこそ");
INSERT INTO `v1_026e5b95fc1a2aad454f3bcf77a61bafb6199d18ea0c41e08d78a17d68ccb287` VALUES (0, "vo_minigame_1013_icon_1_020_001", "vo_minigame_1013_icon_2_020_001", 8, 1, 13, 6, "みんなに力を！", 3000, "ナナカちゃんに\nお任せあれ");
INSERT INTO `v1_026e5b95fc1a2aad454f3bcf77a61bafb6199d18ea0c41e08d78a17d68ccb287` VALUES (0, "vo_minigame_1013_icon_1_022_001", "vo_minigame_1013_icon_2_022_001", 9, 1, 14, 7, "任せてくれたまえ", 3000, "はっはっは！\n任せろ！");
INSERT INTO `v1_026e5b95fc1a2aad454f3bcf77a61bafb6199d18ea0c41e08d78a17d68ccb287` VALUES (0, "vo_minigame_1013_icon_1_023_001", "vo_minigame_1013_icon_2_023_001", 10, 1, 15, 8, "ほな、いきまひょか", 3000, "どんどんいくわよ");
